import itertools
class Solution:
    def maxScore(self, n, edges):
        if n == 1:
            return 0
        best = 0
        for perm in itertools.permutations(range(1, n + 1)):
            s = 0
            for a, b in edges:
                s += perm[a] * perm[b]
            if s > best:
                best = s
        return best

