from collections import deque
class Solution:
    def maxScore(self, n, edges):
        if n == 1:
            return 0
        m = len(edges)
        vals = list(range(1, n + 1))
        is_cycle = (m == n)
        if not is_cycle:
            dq = deque()
            left = True
            for v in reversed(vals):
                if left:
                    dq.appendleft(v)
                else:
                    dq.append(v)
                left = not left
            seq = list(dq)
            return sum(seq[i] * seq[i + 1] for i in range(len(seq) - 1))
        else:
            dq = deque([vals[-1]])
            left = True
            for v in reversed(vals[:-1]):
                if left:
                    dq.appendleft(v)
                else:
                    dq.append(v)
                left = not left
            arr = list(dq)
            return sum(arr[i] * arr[(i + 1) % n] for i in range(n))

