var maxScore = function(n, edges) {
    if (n === 1) return 0;
    const m = edges.length;
    const vals = [];
    for (let i = 1; i <= n; i++) vals.push(i);
    const isCycle = (m === n);
    const dq = [];
    let left = true;
    if (!isCycle) {
        for (let i = vals.length - 1; i >= 0; i--) {
            if (left) dq.unshift(vals[i]); else dq.push(vals[i]);
            left = !left;
        }
        let s = 0;
        for (let i = 0; i + 1 < dq.length; i++) s += dq[i] * dq[i + 1];
        return s;
    } else {
        dq.push(vals[vals.length - 1]);
        for (let i = vals.length - 2; i >= 0; i--) {
            if (left) dq.unshift(vals[i]); else dq.push(vals[i]);
            left = !left;
        }
        let s = 0;
        for (let i = 0; i < n; i++) s += dq[i] * dq[(i + 1) % n];
        return s;
    }
};
